import  React, { Component } from 'react';
import { Blog } from './blog';

export class Projects extends Component {
    state = {
        idx: 0,
        transition: 0
    }

    constructor(props) {
        super(props);
        this.classes = [PC, OTHER, OTHER]
        this.names = ['pc', 'other', 'third']
    }

    scroll(idx) {
        if(idx === this.state.idx) return
        if (this.timeout) clearTimeout(this.timeout)
        let diff = idx > this.state.idx ? -1 : 1
        this.setState({
            idx: this.state.idx - diff,
            transition: diff
        }, () => {
            this.timeout = setTimeout(() => this.setState({
                transition: 0,
            }), 350)
        })

    }

    render() {
        return <div style={{
            marginTop: '4vh'
        }}>
            <div style={{
                display: 'inline-block',
                width: '100vw'
            }}>
                {this.names.map((n, idx) => <div
                    style={{
                        display: 'inline-block',
                        textAlign: 'center',
                        width: `${100/this.names.length}%`,
                        opacity: idx === this.state.idx ? 1 : .5
                    }}
                    key={idx}
                >
                    {n}
                </div>)}
            </div>
            <div className={
                this.state.transition === -1 ? 'center-from-right' :
                (this.state.transition === 1 ? 'center-from-left' : 'center-stop')
            }
            style={{
                width: '60%',
                zIndex: 3,
                position: 'absolute',
                left: '20%',
                right: '20%',
            }}>
                {React.createElement(this.classes[this.state.idx])}
            </div>
            {/* RIGHT */}
            {this.state.idx < this.classes.length - 1 &&
                <div className={
                    this.state.transition === -1 ? "right-from-right" :
                    (this.state.transition === 1 ? "right-from-left" : 'right-stop')}
                    onClick={() => this.scroll(this.state.idx + 1)}
                    style={{
                        position: 'absolute',
                        marginTop: '1vh',
                        margin: 'auto',
                        zIndex: 2,
                        width: '60%',
                        left: 0,
                        right: 0
                }}>
                    {React.createElement(this.classes[this.state.idx + 1])}
                </div>
            }
            {/* LEFT */}
            {this.state.idx > 0 &&
                <div className={
                        this.state.transition === -1 ? "left-from-right" :
                        (this.state.transition === 1 ? "left-from-left" : 'left-stop')}
                    onClick={() => this.scroll(this.state.idx - 1)}
                    style={{
                        position: 'absolute',
                        marginTop: '1vh',
                        margin: 'auto',
                        zIndex: 2,
                        width: '60%',
                        left: 0,
                        right: 0
                }}>
                    {React.createElement(this.classes[this.state.idx -1])}
                </div>
            }
        </div>
    }
}

