import  React, { Component } from 'react';

export class Blog extends Component {
    render() {
        const img_names = Array.isArray(this.props.image) ? this.props.image : [this.props.image]
        const images = img_names.map(i => <img src={`${process.env.PUBLIC_URL}/images/${i}`} alt='not found' />)
        return  <div className='post'>
        <p> {this.props.children} </p>
        <p style={{
            float: 'right',
            fontSize: '50%'
        }}> {this.props.date} </p>
        <br></br>
        {this.props.image &&  images}
        <hr class="dotted"></hr>
    </div>
    }
}